package com.example.midterm.ui.admin

import android.net.Uri
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.midterm.data.model.Role
import com.example.midterm.data.model.User
import com.example.midterm.data.repository.UserRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

sealed class AdminUiState {
    object Loading : AdminUiState()
    data class Success(val users: List<User>) : AdminUiState()
    data class Error(val message: String) : AdminUiState()
}

class AdminViewModel : ViewModel() {

    private val repository = UserRepository()

    private val _uiState = MutableStateFlow<AdminUiState>(AdminUiState.Loading)
    val uiState: StateFlow<AdminUiState> = _uiState

    private val _actionMessage = MutableStateFlow<String?>(null)
    val actionMessage: StateFlow<String?> = _actionMessage

    init {
        loadUsers()
    }

    fun loadUsers() {
        viewModelScope.launch {
            _uiState.value = AdminUiState.Loading
            try {
                val users = repository.getAllUsers()
                _uiState.value = AdminUiState.Success(users)
            } catch (e: Exception) {
                _uiState.value = AdminUiState.Error("Không thể tải danh sách: ${e.message}")
            }
        }
    }

    fun createUser(username: String, password: String, role: Role, imageUri: Uri? = null) {
        viewModelScope.launch {
            try {
                val result = repository.createUser(username.trim(), password.trim(), role)
                result.fold(
                    onSuccess = { user ->
                        if (imageUri != null) {
                            repository.updateUser(user, imageUri)
                        }
                        _actionMessage.value = "Tạo tài khoản thành công"
                        loadUsers()
                    },
                    onFailure = { _actionMessage.value = it.message }
                )
            } catch (e: Exception) {
                _actionMessage.value = "Lỗi: ${e.message}"
            }
        }
    }

    fun updateUser(user: User, imageUri: Uri? = null) {
        viewModelScope.launch {
            try {
                val result = repository.updateUser(user, imageUri)
                result.fold(
                    onSuccess = {
                        _actionMessage.value = "Cập nhật thành công"
                        loadUsers()
                    },
                    onFailure = { _actionMessage.value = it.message }
                )
            } catch (e: Exception) {
                _actionMessage.value = "Lỗi: ${e.message}"
            }
        }
    }

    fun deleteUser(userId: String) {
        viewModelScope.launch {
            try {
                val result = repository.deleteUser(userId)
                result.fold(
                    onSuccess = {
                        _actionMessage.value = "Xóa tài khoản thành công"
                        loadUsers()
                    },
                    onFailure = { _actionMessage.value = it.message }
                )
            } catch (e: Exception) {
                _actionMessage.value = "Lỗi: ${e.message}"
            }
        }
    }

    fun clearActionMessage() {
        _actionMessage.value = null
    }
}

package com.example.midterm.ui.admin

import android.net.Uri
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.midterm.data.model.Role
import com.example.midterm.data.model.User
import com.example.midterm.data.repository.UserRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

sealed class AdminUiState {
    object Loading : AdminUiState()
    data class Success(val users: List<User>) : AdminUiState()
    data class Error(val message: String) : AdminUiState()
}

class AdminViewModel : ViewModel() {

    private val repository = UserRepository()

    private val _uiState = MutableStateFlow<AdminUiState>(AdminUiState.Loading)
    val uiState: StateFlow<AdminUiState> = _uiState

    private val _actionMessage = MutableStateFlow<String?>(null)
    val actionMessage: StateFlow<String?> = _actionMessage

    init {
        loadUsers()
    }

    fun loadUsers() {
        viewModelScope.launch {
            _uiState.value = AdminUiState.Loading
            try {
                val users = repository.getAllUsers()
                _uiState.value = AdminUiState.Success(users)
            } catch (e: Exception) {
                _uiState.value = AdminUiState.Error("Không thể tải danh sách: ${e.message}")
            }
        }
    }

    fun createUser(username: String, password: String, role: Role, imageUri: Uri? = null) {
        viewModelScope.launch {
            try {
                val result = repository.createUser(username.trim(), password.trim(), role)
                result.fold(
                    onSuccess = { user ->
                        if (imageUri != null) {
                            // Upload ảnh mới
                            val uploadResult = com.example.midterm.util.ImageUploadService.uploadImage(imageUri)
                            if (uploadResult.isSuccess) {
                                val newImageUrl = uploadResult.getOrNull() ?: ""
                                val userWithImage = user.copy(imageUrl = newImageUrl)
                                repository.updateUser(userWithImage)
                            }
                        }
                        _actionMessage.value = "Tạo tài khoản thành công"
                        loadUsers()
                    },
                    onFailure = { _actionMessage.value = it.message }
                )
            } catch (e: Exception) {
                _actionMessage.value = "Lỗi: ${e.message}"
            }
        }
    }

    fun updateUser(user: User, imageUri: Uri? = null) {
        viewModelScope.launch {
            try {
                var updatedUser = user

                // Xử lý upload ảnh nếu có
                if (imageUri != null) {
                    val uploadResult = com.example.midterm.util.ImageUploadService.uploadImage(imageUri)
                    if (uploadResult.isSuccess) {
                        val newImageUrl = uploadResult.getOrNull() ?: ""
                        updatedUser = updatedUser.copy(imageUrl = newImageUrl)
                    }
                }

                val result = repository.updateUser(updatedUser)
                result.fold(
                    onSuccess = {
                        _actionMessage.value = "Cập nhật thành công"
                        loadUsers()
                    },
                    onFailure = { _actionMessage.value = it.message }
                )
            } catch (e: Exception) {
                _actionMessage.value = "Lỗi: ${e.message}"
            }
        }
    }

    fun deleteUser(userId: String) {
        viewModelScope.launch {
            try {
                val result = repository.deleteUser(userId)
                result.fold(
                    onSuccess = {
                        _actionMessage.value = "Xóa tài khoản thành công"
                        loadUsers()
                    },
                    onFailure = { _actionMessage.value = it.message }
                )
            } catch (e: Exception) {
                _actionMessage.value = "Lỗi: ${e.message}"
            }
        }
    }

    fun clearActionMessage() {
        _actionMessage.value = null
    }
}

package com.example.midterm.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import com.example.midterm.ui.admin.AdminDashboardScreen
import com.example.midterm.ui.auth.LoginScreen
import com.example.midterm.ui.auth.RegisterScreen
import com.example.midterm.ui.user.UserDashboardScreen
import com.example.midterm.util.UserSessionManager

@Composable
fun AppNavigation(navController: NavHostController) {
    NavHost(
        navController = navController,
        startDestination = Routes.LOGIN
    ) {
        composable(Routes.LOGIN) {
            LoginScreen(
                onNavigateToRegister = { navController.navigate(Routes.REGISTER) },
                onLoginSuccess = { role ->
                    val dest = if (role.name == "ADMIN") Routes.ADMIN_DASHBOARD else Routes.USER_DASHBOARD
                    navController.navigate(dest) {
                        popUpTo(Routes.LOGIN) { inclusive = true }
                    }
                }
            )
        }

        composable(Routes.REGISTER) {
            RegisterScreen(
                onNavigateToLogin = { navController.navigateUp() },
                onRegisterSuccess = {
                    navController.navigate(Routes.USER_DASHBOARD) {
                        popUpTo(Routes.LOGIN) { inclusive = true }
                    }
                }
            )
        }

        composable(Routes.ADMIN_DASHBOARD) {
            AdminDashboardScreen(
                onLogout = {
                    navController.navigate(Routes.LOGIN) {
                        popUpTo(0) { inclusive = true }
                    }
                }
            )
        }

        composable(Routes.USER_DASHBOARD) {
            UserDashboardScreen(
                onLogout = {
                    UserSessionManager.logout()
                    navController.navigate(Routes.LOGIN) {
                        popUpTo(0) { inclusive = true }
                    }
                }
            )
        }
    }
}

