package com.example.midterm.util

import android.content.Context
import android.net.Uri
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.MultipartBody
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONObject

@Suppress("unused", "MemberVisibilityCanBePrivate")
object CloudinaryService {

    // ⚠️ Thay đổi với account Cloudinary của bạn
    private const val CLOUD_NAME = "dvaykfaby"
    private const val UPLOAD_PRESET = "your_upload_preset"
    private const val CLOUDINARY_URL = "https://api.cloudinary.com/v1_1"

    private val client = OkHttpClient()
    private var context: Context? = null

    fun init(context: Context) {
        this.context = context
    }

    @Suppress("BlockingMethodInNonBlockingContext")
    suspend fun uploadImage(uri: Uri): Result<String> = withContext(Dispatchers.IO) {
        return@withContext try {
            val ctx =
                context ?: return@withContext Result.failure(Exception("Context not initialized"))

            // Đọc file từ URI
            val inputStream = ctx.contentResolver.openInputStream(uri)
                ?: return@withContext Result.failure(Exception("Không thể mở file"))

            val fileData = inputStream.readBytes()
            inputStream.close()

            val requestBody = MultipartBody.Builder()
                .setType(MultipartBody.FORM)
                .addFormDataPart(
                    "file",
                    "image.jpg",
                    okhttp3.RequestBody.create("image/jpeg".toMediaType(), fileData)
                )
                .addFormDataPart("upload_preset", UPLOAD_PRESET)
                .build()

            val request = Request.Builder()
                .url("$CLOUDINARY_URL/$CLOUD_NAME/image/upload")
                .post(requestBody)
                .build()

            client.newCall(request).execute().use { response ->
                if (response.isSuccessful) {
                    val bodyString = response.body?.string() ?: ""
                    val json = JSONObject(bodyString)
                    val url = json.optString("secure_url", "")

                    if (url.isNotEmpty()) {
                        Result.success(url)
                    } else {
                        Result.failure(Exception("Không nhận được URL"))
                    }
                } else {
                    Result.failure(Exception("Upload thất bại: ${response.code}"))
                }
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.midterm.util

import android.content.Context
import android.net.Uri
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File
import java.util.UUID

@Suppress("unused", "MemberVisibilityCanBePrivate")
object CloudinaryService {

    private var context: Context? = null
    private const val IMAGES_DIR = "user_images"

    fun init(context: Context) {
        this.context = context
        // Tạo folder cho ảnh
        val imagesFolder = File(context.filesDir, IMAGES_DIR)
        if (!imagesFolder.exists()) {
            imagesFolder.mkdirs()
        }
    }

    @Suppress("BlockingMethodInNonBlockingContext")
    suspend fun uploadImage(uri: Uri): Result<String> = withContext(Dispatchers.IO) {
        return@withContext try {
            val ctx = context ?: return@withContext Result.failure(Exception("Context not initialized"))

            // Đọc file từ URI
            val inputStream = ctx.contentResolver.openInputStream(uri)
                ?: return@withContext Result.failure(Exception("Không thể mở file"))

            val fileName = "img_${UUID.randomUUID()}.jpg"
            val imageFile = File(ctx.filesDir, "$IMAGES_DIR/$fileName")

            inputStream.use { input ->
                imageFile.outputStream().use { output ->
                    input.copyTo(output)
                }
            }

            // Trả về path file
            Result.success(imageFile.absolutePath)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.midterm.util

import android.content.Context
import android.net.Uri
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File
import java.util.UUID

@Suppress("unused", "MemberVisibilityCanBePrivate")
object ImageUploadService {

    private var context: Context? = null
    private const val IMAGES_DIR = "user_images"

    fun init(context: Context) {
        this.context = context
        // Tạo folder cho ảnh
        val imagesFolder = File(context.filesDir, IMAGES_DIR)
        if (!imagesFolder.exists()) {
            imagesFolder.mkdirs()
        }
    }

    @Suppress("BlockingMethodInNonBlockingContext")
    suspend fun uploadImage(uri: Uri): Result<String> = withContext(Dispatchers.IO) {
        return@withContext try {
            val ctx = context ?: return@withContext Result.failure(Exception("Context not initialized"))

            // Đọc file từ URI
            val inputStream = ctx.contentResolver.openInputStream(uri)
                ?: return@withContext Result.failure(Exception("Không thể mở file"))

            val fileName = "img_${UUID.randomUUID()}.jpg"
            val imageFile = File(ctx.filesDir, "$IMAGES_DIR/$fileName")

            inputStream.use { input ->
                imageFile.outputStream().use { output ->
                    input.copyTo(output)
                }
            }

            // Trả về path file
            Result.success(imageFile.absolutePath)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.midterm.util

import android.content.Context
import android.net.Uri
import android.os.Environment
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File
import java.util.UUID

@Suppress("unused", "MemberVisibilityCanBePrivate")
object ImageUploadService {

    private var context: Context? = null
    private const val IMAGES_DIR = "MidtermImages"

    fun init(context: Context) {
        this.context = context
        // Tạo folder trong Downloads
        val imagesFolder = File(
            Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOWNLOADS),
            IMAGES_DIR
        )
        if (!imagesFolder.exists()) {
            imagesFolder.mkdirs()
        }
    }

    @Suppress("BlockingMethodInNonBlockingContext")
    suspend fun uploadImage(uri: Uri): Result<String> = withContext(Dispatchers.IO) {
        return@withContext try {
            val ctx = context ?: return@withContext Result.failure(Exception("Context not initialized"))

            // Đọc file từ URI
            val inputStream = ctx.contentResolver.openInputStream(uri)
                ?: return@withContext Result.failure(Exception("Không thể mở file"))

            val fileName = "img_${UUID.randomUUID()}.jpg"
            val downloadsDir = Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOWNLOADS)
            val imageFile = File(downloadsDir, "$IMAGES_DIR/$fileName")

            inputStream.use { input ->
                imageFile.outputStream().use { output ->
                    input.copyTo(output)
                }
            }

            // Trả về path file
            Result.success(imageFile.absolutePath)

        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

